# Connection pool (min 1, max 10 connections)
_connection_pool = None


def get_connection_pool():
    """Initialize and return the connection pool (singleton)."""
    global _connection_pool
    if _connection_pool is None or _connection_pool.closed:
        _connection_pool = psycopg2.pool.ThreadedConnectionPool(
            minconn=1,
            maxconn=10,
            **DB_CONFIG,
        )
    return _connection_pool


def get_connection():
    """Get a single database connection from the pool."""
    pool = get_connection_pool()
    return pool.getconn()


def release_connection(conn):
    """Return a connection back to the pool."""
    pool = get_connection_pool()
    pool.putconn(conn)


@contextmanager
def get_db_connection():
    """Context manager for database connections. Auto-releases back to pool."""
    conn = get_connection()
    try:
        yield conn
        conn.commit()
    except Exception:
        conn.rollback()
        raise
    finally:
        release_connection(conn)


@contextmanager
def get_db_cursor(commit=True):
    """Context manager that provides a cursor and handles commit/rollback."""
    with get_db_connection() as conn:
        cursor = conn.cursor()
        try:
            yield cursor
            if commit:
                conn.commit()
        except Exception:
            conn.rollback()
            raise
        finally:
            cursor.close()


def execute_query(query, params=None, fetch=True):
    """Execute a query and optionally return results."""
    with get_db_cursor() as cursor:
        cursor.execute(query, params)
        if fetch:
            columns = [desc[0] for desc in cursor.description]
            rows = cursor.fetchall()
            return [dict(zip(columns, row)) for row in rows]
        return None


def execute_many(query, params_list):
    """Execute a query with multiple parameter sets (bulk insert, etc.)."""
    with get_db_cursor() as cursor:
        cursor.executemany(query, params_list)
        return cursor.rowcount


def close_pool():
    """Close all connections in the pool. Call on app shutdown."""
    global _connection_pool
    if _connection_pool is not None and not _connection_pool.closed:
        _connection_pool.closeall()
        _connection_pool = None


def test_connection():
    """Test the database connection and print status."""
    try:
        with get_db_cursor() as cursor:
            cursor.execute("SELECT version();")
            version = cursor.fetchone()[0]
            print(f"Connected successfully!")
            print(f"PostgreSQL version: {version}")
            return True
    except psycopg2.OperationalError as e:
        print(f"Connection failed: {e}")
        return False


